<script>
let currentFaction = 'survivor';
let cfg = {
    s_g: 'male', s_gt: '男性', s_x: 'cult',
    h_g: '男性', h_gt: '男性', h_x: '大祭司'
};

function switchFaction(faction) {
    currentFaction = faction;
    const btnS = document.getElementById('btn-survivor');
    const btnH = document.getElementById('btn-hunter');
    const formS = document.getElementById('form-survivor');
    const formH = document.getElementById('form-hunter');
    const submitBtn = document.getElementById('s-btn');
    const panel = document.getElementById('c-pan');

    if(faction === 'survivor') {
        btnS.classList.add('active-survivor');
        btnH.classList.remove('active-hunter');
        formS.classList.remove('hidden-section');
        formH.classList.add('hidden-section');

        panel.classList.remove('mode-hunter'); // 移除猎杀者主题，恢复默认幽绿

        submitBtn.innerText = "生 效 档 案 (求生模式)";
    } else {
        btnH.classList.add('active-hunter');
        btnS.classList.remove('active-survivor');
        formH.classList.remove('hidden-section');
        formS.classList.add('hidden-section');

        panel.classList.add('mode-hunter'); // 添加猎杀者主题类，触发猩红CSS变量

        submitBtn.innerText = "降 临 黑 木 林 (猎杀模式)";
    }
}

function setOpt(grp, val, txt) {
    const btns = document.querySelectorAll('.o-btn[data-g="'+grp+'"]');
    btns.forEach(b => b.classList.remove('active'));
    event.currentTarget.classList.add('active');

    cfg[grp] = val;
    if(txt) cfg[grp+'t'] = txt;
}

function submitForm() {
    const btn = document.getElementById('s-btn');
    if(btn.disabled) return;
    btn.disabled = true;

    let commandText = "";

    if(currentFaction === 'survivor') {
        btn.innerText = "命运锁定中...";
        const trait = document.getElementById('sel-survivor').value;
        let encFull = "";
        let encName = "";
        if(cfg.s_g === 'male' && cfg.s_x === 'cult') { encFull = "敌人锁定：**全女性狂热信徒**"; encName = "全女性狂热信徒"; }
        else if(cfg.s_g === 'female' && cfg.s_x === 'cult') { encFull = "敌人锁定：**全男性狂热信徒**"; encName = "全男性狂热信徒"; }
        else if(cfg.s_g === 'male' && cfg.s_x === 'monster') { encFull = "敌人锁定：**发情期的雌性变异体**"; encName = "发情期雌性变异体"; }
        else { encFull = "敌人锁定：**发情期的雄性变异体**"; encName = "发情期雄性变异体"; }

        commandText = `*[系统提示]* 玩家【求生者档案】已建立。
目标性别：**${cfg.s_gt}**
求生特质：**${trait}**
${encFull}

[导演核心指令：求生模式]
1. 场景强制核对：房间内共有5人（玩家、布兰妮、杰西卡、克洛伊、艾米丽）。不许凭空消失。
2. 剧情控制：布兰妮将门拉开了一条缝。禁止直接大屠杀，描写门缝外恐怖的视觉/听觉暗示。
3. 选项抛出：维持译制片腔调，在输出下方代码块前，输出首尾闭合的 [QTE] 面板。
4. 系统级强制激活：你必须在本次回复的最末尾，逐字原样复制以下代码块输出（不要删减任何字符）：
<UpdateVariable>
<JSONPatch>
[
  { "op": "replace", "path": "/世界/当前模式", "value": "求生者" },
  { "op": "replace", "path": "/世界/敌方情报", "value": "${encName}" },
  { "op": "replace", "path": "/玩家/求生特质", "value": "${trait}" }
]
</JSONPatch>
</UpdateVariable>`;
    } else {
        btn.innerText = "意识降临中...";
        const trait = document.getElementById('sel-hunter').value;

        commandText = `*[系统提示]* 玩家【猎杀者档案】已建立。
宿主形态：**${cfg.h_g} ${cfg.h_x}**
狩猎天赋：**${trait}**

[导演核心指令：猎杀模式]
1. 场景强制点名：门内共有四只羔羊（布兰妮、杰西卡、克洛伊、艾米丽）。绝对禁止凭空消失！描写布兰妮拉开门缝看到你时扭曲的脸，及另外三人极度恐慌的反应。
2. 力量碾压：玩家拥有绝对优势，猎物的所有反抗与逃跑尝试都显得极其可笑和徒劳。
3. 选项抛出：维持恶毒的译制片腔调，在输出下方代码块前，输出首尾闭合的 [QTE] 面板。
4. 系统级强制激活：你必须在本次回复的最末尾，逐字原样复制以下代码块输出（不要删减任何字符）：
<UpdateVariable>
<JSONPatch>
[
  { "op": "replace", "path": "/世界/当前模式", "value": "猎杀者" },
  { "op": "replace", "path": "/玩家/猎杀形态", "value": "${cfg.h_g}${cfg.h_x}" },
  { "op": "replace", "path": "/玩家/狩猎天赋", "value": "${trait}" }
]
</JSONPatch>
</UpdateVariable>`;
    }

    try {
        const input = window.parent.document.querySelector('#send_textarea');
        const sendBtn = window.parent.document.querySelector('#send_but');
        if (input) {
            input.value = commandText;
            input.dispatchEvent(new Event('input', { bubbles: true }));
            if(sendBtn) setTimeout(() => { sendBtn.click(); }, 300);
        }
    } catch (e) {
        console.error(e);
    }

    // 触发终局特效
    const panel = document.getElementById('c-pan');
    panel.classList.add('end-shatter');

    setTimeout(() => {
        document.getElementById('f-area').style.display = 'none';
        const msg = document.getElementById('b-msg');
        msg.style.display = 'block';

