    function populateCharacterData() {
      const all_variables = typeof getAllVariables === 'function' ? getAllVariables() : {};

      // === 世界状态 ===
      const mode = _.get(all_variables, 'stat_data.世界.当前模式', '待确认');
      const time = _.get(all_variables, 'stat_data.世界.当前时间', '00:00');
      const stage = _.get(all_variables, 'stat_data.世界.游戏阶段', '暗中窥视 / 危险逼近');
