}

body { background-color: transparent; margin: 0; padding: 10px; font-family: var(--font-main); }

/* ================= 容器与心跳动画 ================= */
.qte-container {
  display: flex; flex-direction: column;
  background: linear-gradient(135deg, var(--bg-grad-1) 0%, var(--bg-grad-2) 100%);
  border: 2px solid var(--border-main); border-radius: 4px; padding: 15px;
  position: relative; max-width: 600px; margin: 15px auto; overflow: hidden;
  animation: c-hb 2s infinite ease-in-out;
  transition: all 0.5s ease;
}

@keyframes c-hb {
  0%, 100% { box-shadow: 0 0 20px var(--glow-main), inset 0 0 30px rgba(0,0,0,0.8); border-color: var(--border-main); }
  50% { box-shadow: 0 0 35px var(--glow-strong), inset 0 0 50px rgba(0,0,0,0.9); border-color: var(--text-warning); transform: scale(1.005); }
}

/* 噪点遮罩 */
.qte-container::before {
  content: ''; position: absolute; top: 0; left: 0; right: 0; bottom: 0;
  background: url('data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" width="100%" height="100%"><filter id="n"><feTurbulence type="fractalNoise" baseFrequency="0.8" numOctaves="3" stitchTiles="stitch"/></filter><rect width="100%" height="100%" filter="url(%23n)" opacity="0.15"/></svg>');
  mix-blend-mode: color-burn; pointer-events: none; z-index: 0;
}

.qte-container::after {
  content: ''; position: absolute; top: 0; left: 0; right: 0; bottom: 0;
  background: radial-gradient(circle, transparent 40%, rgba(0,0,0,0.8) 100%);
