/* ================= 倒计时进度条 ================= */
.qte-timer-wrap { order: 1; margin-bottom: 15px; }
.qte-timer-bar {
  width: 100%; height: 12px; background-color: #000; border-radius: 2px;
  overflow: hidden; border: 1px solid var(--border-main); box-shadow: inset 0 0 8px #000;
  position: relative; transition: border-color 0.5s;
}
.qte-timer-fill {
  height: 100%; width: 100%; transition: width 0.05s linear;
  background: repeating-linear-gradient(-45deg, var(--timer-bg-1), var(--timer-bg-1) 10px, var(--timer-bg-2) 10px, var(--timer-bg-2) 20px);
