  box-shadow: 0 0 10px var(--text-warning);
}
@keyframes m-str { 0% { background-position: 0 0; } 100% { background-position: 28px 0; } }

.qte-countdown {
  text-align: center; color: var(--text-warning); font-size: 1.1em; font-weight: bold;
  margin-top: 5px; letter-spacing: 2px; text-shadow: 0 0 5px var(--glow-strong);
