}

/* ================= 惊恐模式 (最后3秒) ================= */
.panic-mode .qte-countdown { animation: s-gl 0.2s infinite; color: #fff; }
.panic-mode.qte-container { animation: p-shk 0.1s infinite; box-shadow: 0 0 40px var(--glow-strong), inset 0 0 60px rgba(0,0,0,0.9); border-color: var(--danger-color); }

@keyframes s-gl {
  0%, 100% { transform: translate(0); text-shadow: -2px 0 var(--danger-color), 2px 0 cyan; }
  20% { transform: translate(-3px, 2px); text-shadow: 2px 0 var(--danger-color), -2px 0 cyan; }
  40% { transform: translate(3px, -2px); text-shadow: 3px 0 var(--danger-color), -3px 0 cyan; }
  60% { transform: translate(-2px, -3px); text-shadow: -3px 0 var(--danger-color), 3px 0 cyan; }
  80% { transform: translate(2px, 3px); text-shadow: 2px 0 var(--danger-color), -2px 0 cyan; }
}
@keyframes p-shk { 0%, 100% { transform: translateX(0); } 25% { transform: translateX(-2px) rotate(-0.5deg); } 75% { transform: translateX(2px) rotate(0.5deg); } }

/* ================= 动作按钮 ================= */
.button-group { display: flex; flex-direction: column; gap: 10px; order: 2; }
.action-btn {
  box-sizing: border-box; border-radius: 2px; padding: 12px 15px; font-size: 0.95em;
  text-align: left; width: 100%; transition: all 0.2s ease;
  border: 1px solid var(--border-main); color: var(--text-main);
  background: linear-gradient(90deg, rgba(0,0,0,0.6) 0%, rgba(0,0,0,0.8) 100%);
  font-family: inherit; cursor: pointer; position: relative; overflow: hidden;
}
.action-btn::before {
  content: ''; position: absolute; top: 0; left: -100%; width: 100%; height: 100%;
  background: linear-gradient(90deg, transparent, var(--glow-main), transparent);
  transition: left 0.3s ease; z-index: 0;
}
.action-btn:hover::before { left: 100%; }
.action-btn:hover {
  background: rgba(0,0,0,0.9); border-color: var(--text-warning); color: #fff;
  box-shadow: 0 0 15px var(--glow-main); text-shadow: 0 0 5px var(--glow-strong);
  transform: scale(1.02);
}

.action-btn.active {
  background-color: var(--border-main); color: #fff; border-color: var(--text-warning);
  box-shadow: 0 0 20px var(--glow-strong), inset 0 0 10px #000; animation: p-act 1s infinite;
}
@keyframes p-act { 0%, 100% { background-color: var(--border-main); } 50% { background-color: var(--timer-bg-1); } }

.action-btn:disabled { background: #050505; border-color: #222; color: #444; cursor: not-allowed; box-shadow: none; transform: none; }
.action-btn:disabled::before { display: none; }

/* ================= 折叠/展开逻辑 ================= */
.qte-summary { list-style: none; cursor: pointer; order: 4; margin-top: 15px; text-align: center; z-index: 2; }
