.qte-container:not([open]) .qte-header, .qte-container:not([open]) .qte-timer-wrap, .qte-container:not([open]) .button-group, .qte-container:not([open])::before, .qte-container:not([open])::after, .qte-container:not([open]) .qte-status-bar { display: none; }

.qte-collapse-btn {
  display: inline-block; color: var(--danger-color); font-size: 1.1em; font-weight: bold;
  border: 1px solid var(--danger-color); background: rgba(0,0,0,0.8); padding: 10px 20px;
