    fl.style.width=Math.max(0,(tl/TT)*100)+'%';
    if(tl<=3.0&&!isP&&!isE)mb.classList.add('panic-mode');
    else mb.classList.remove('panic-mode');
}

function sT(){
    if(isE)return;
    if(tI!==null)clearInterval(tI);
    lTs=Date.now();
    tI=setInterval(function(){
        var nw=Date.now();
        tl-=(nw-lTs)/1000;
        lTs=nw;
        uU();
        if(tl<=0){tl=0;uU();clearInterval(tI);tI=null;tP();}
    },30);
}

mb.addEventListener('toggle', function() {
    if(mb.open && !isStarted && !isE) {
        isStarted = true;
        sT();
    }
});

pb.onclick=function(e){
    e.preventDefault();
    if(isE || !isStarted)return;
    isP=!isP;
    if(isP){
        if(tI!==null){clearInterval(tI);tI=null;}
        pb.innerHTML='▶️ 恢复呼吸';
        pb.style.color='var(--text-main)'; pb.style.borderColor='var(--border-main)';
        wt.style.animation='none';wt.style.opacity='0.3';
        fl.style.animation='none';mb.style.animation='none';
        mb.classList.remove('panic-mode');
    }else{
        sT();
        pb.innerHTML='⏸️ 强行屏息';
        pb.style.color='var(--text-warning)'; pb.style.borderColor='var(--border-main)';
        wt.style.animation='t-jit 0.4s infinite';wt.style.opacity='1';
        fl.style.animation='m-str 1s linear infinite';mb.style.animation='c-hb 2s infinite ease-in-out';
    }
};

uU();

function eA(bo,ta){
    if(isE)return;
    isE=true;
    if(tI!==null){clearInterval(tI);tI=null;}
    mb.classList.remove('panic-mode');mb.style.animation='none';
    var bs=document.querySelectorAll('#button-container .action-btn');
    for(var j=0;j<bs.length;j++){bs[j].disabled=true;bs[j].classList.remove('active');}
    bo.classList.add('active');

    // 让成功点击的颜色回退到纯净的CSS变量控制，避免硬编码
    fl.style.background='var(--timer-bg-1)'; fl.style.boxShadow='none'; fl.style.animation='none';
    wt.style.color='#fff';wt.innerText='>> 动作已锁定 <<';
    wt.style.animation='none';pb.style.display='none';

    // 主动点击的发送语句也带上一点点翻译腔
    var actMsg = "*[执行动作]* 看在上帝的份上，我别无选择只能："+ta+"。请结算这该死的后果。";
    sM(actMsg, true);
}

function tP(){
    if(isE)return;
    isE=true;
    if(tI!==null){clearInterval(tI);tI=null;}
    mb.classList.remove('panic-mode');
    var bs=document.querySelectorAll('#button-container .action-btn');
    for(var j=0;j<bs.length;j++){bs[j].disabled=true;}

    // 失败锁定：边框变为绝对危险色
    mb.style.borderColor='var(--danger-color)';mb.style.animation='none';
    pb.style.display='none';
    fl.style.background='#222';fl.style.boxShadow='none';

    // 根据模式生成不同的战败/超时文案
    var badEndText = "";
    if(currentMode === '猎杀者') {
        wt.innerText='❌ 错失良机：羔羊获得了喘息 ❌';
        wt.style.animation='none';wt.style.color='#ffaa00';
        badEndText = "*[QTE判定失败]* 见鬼，我在干什么？这转瞬即逝的十秒钟里，我居然因为想要多欣赏一会羔羊的丑态而错过了最佳的出手时机！老伙计，请立刻结算这次该死的迟疑让我付出了什么代价。";
    } else {
        wt.innerText='❌ 绝望：你被黑暗吞噬了 ❌';
        wt.style.animation='none';wt.style.color='var(--danger-color)';
        badEndText = "*[QTE判定失败]* 哦，我的上帝！这见鬼的十秒钟简直像是一个世纪！极度的恐惧彻底攥紧了我可怜的心脏，我就像个吓傻的白痴一样僵在原地，一步也挪不开……该死，请执行最残忍的绝境判定与捕获惩罚！";
    }

    sM(badEndText, true);
}

function sM(msg,at){
    try{
        var cd='/send '+msg+(at?' | /trigger':'');
        if(typeof triggerSlash==='function'){triggerSlash(cd);}
        else{
            var ip=window.parent.document.querySelector('#send_textarea');
            if(ip){
                ip.value=msg;
                ip.dispatchEvent(new Event('input',{bubbles:true}));
                if(at){
                    var bn=window.parent.document.querySelector('#send_but');
                    if(bn)setTimeout(function(){bn.click();},300);
                }
            }
        }
    }catch(er){}
}
},50);
</script>
</body>
</html>
